            { group: 'Generative Edge & Power Tools', items: ['Superhuman AI (Thread summarization and Tone-matching draft generation)', 'Native Read Receipts and Click Tracking', 'Advanced "Snippets" (dynamic variable templates)', 'Aggressive Undo-Send and Scheduled Follow-ups'] }
